import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ProductService } from '../../services/product.service';
import { Product } from '../../models/product.model';

@Component({
  selector: 'app-product-list',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './product-list.html',
  styleUrl: './product-list.css',
})
export class ProductListComponent implements OnInit {
  private productService = inject(ProductService);
  products: Product[] = [];
  selectedProduct: Product | null = null;
  showForm = false;
  isEditing = false;

  ngOnInit(): void {
    this.productService.getProducts().subscribe(products => {
      this.products = products;
    });
  }

  openAddForm(): void {
    this.showForm = true;
    this.isEditing = false;
    this.selectedProduct = null;
  }

  openEditForm(product: Product): void {
    this.showForm = true;
    this.isEditing = true;
    this.selectedProduct = { ...product };
  }

  closeForm(): void {
    this.showForm = false;
    this.selectedProduct = null;
    this.isEditing = false;
  }

  saveProduct(): void {
    if (this.selectedProduct) {
      if (this.isEditing) {
        this.productService.updateProduct(this.selectedProduct.id, {
          name: this.selectedProduct.name,
          price: this.selectedProduct.price,
          description: this.selectedProduct.description,
          quantity: this.selectedProduct.quantity,
        });
      } else {
        this.productService.addProduct({
          name: this.selectedProduct.name,
          price: this.selectedProduct.price,
          description: this.selectedProduct.description,
          quantity: this.selectedProduct.quantity,
        });
      }
      this.closeForm();
    }
  }

  deleteProduct(id: number): void {
    if (confirm('Are you sure you want to delete this product?')) {
      this.productService.deleteProduct(id);
    }
  }
}
<div class="container">
  <h1>Products Management</h1>

  <button (click)="openAddForm()" class="btn-add">+ Add Product</button>

  <!-- Form Section -->
  <div *ngIf="showForm" class="form-container">
    <h2>{{ isEditing ? 'Edit Product' : 'Add New Product' }}</h2>
    <form (ngSubmit)="saveProduct()" class="product-form">
      <div class="form-group">
        <label>Product Name:</label>
        <input 
          type="text" 
          [(ngModel)]="selectedProduct!.name" 
          name="name"
          required
        />
      </div>

      <div class="form-group">
        <label>Price:</label>
        <input 
          type="number" 
          [(ngModel)]="selectedProduct!.price" 
          name="price"
          required
          step="0.01"
        />
      </div>

      <div class="form-group">
        <label>Description:</label>
        <textarea 
          [(ngModel)]="selectedProduct!.description" 
          name="description"
        ></textarea>
      </div>

      <div class="form-group">
        <label>Quantity:</label>
        <input 
          type="number" 
          [(ngModel)]="selectedProduct!.quantity" 
          name="quantity"
          required
        />
      </div>

      <div class="form-actions">
        <button type="submit" class="btn-save">Save</button>
        <button type="button" (click)="closeForm()" class="btn-cancel">Cancel</button>
      </div>
    </form>
  </div>

  <!-- Products Table -->
  <table class="products-table">
    <thead>
      <tr>
        <th>ID</th>
        <th>Name</th>
        <th>Price</th>
        <th>Description</th>
        <th>Quantity</th>
        <th>Actions</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let product of products">
        <td>{{ product.id }}</td>
        <td>{{ product.name }}</td>
        <td>${{ product.price.toFixed(2) }}</td>
        <td>{{ product.description }}</td>
        <td>{{ product.quantity }}</td>
        <td class="actions">
          <button (click)="openEditForm(product)" class="btn-edit">Edit</button>
          <button (click)="deleteProduct(product.id)" class="btn-delete">Delete</button>
        </td>
      </tr>
    </tbody>
  </table>

  <p *ngIf="products.length === 0" class="no-products">No products available.</p>
</div>
